import sys
sys.path.insert(0, 'protobuf_gen')
import net_pb2
import numpy as np
import torch
import torch.nn as nn

def decode_layer(layer, default_encoding=net_pb2.Weights.Layer.LINEAR16):
    if not layer.HasField('params'):
        return None
    encoding = layer.encoding
    if encoding == 0:
        encoding = default_encoding
    data = layer.params
    dims = list(layer.dims)
    if encoding == net_pb2.Weights.Layer.LINEAR16:
        num_elements = len(data)//2
    elif encoding == net_pb2.Weights.Layer.FLOAT32:
        num_elements = len(data)//4
    elif encoding == net_pb2.Weights.Layer.FLOAT16:
        num_elements = len(data)//2
    elif encoding == net_pb2.Weights.Layer.BFLOAT16:
        num_elements = len(data)//2
    else:
        raise ValueError(f'Unknown encoding {encoding}')
    if not dims:
        dims = [num_elements]
    arr = None
    if encoding == net_pb2.Weights.Layer.FLOAT32:
        arr = np.frombuffer(data, dtype=np.float32).copy()
    elif encoding == net_pb2.Weights.Layer.FLOAT16:
        arr = np.frombuffer(data, dtype=np.float16).astype(np.float32)
    elif encoding == net_pb2.Weights.Layer.BFLOAT16:
        uint16_data = np.frombuffer(data, dtype=np.uint16)
        arr = (uint16_data.astype(np.uint32) << 16).view(np.float32)
    elif encoding == net_pb2.Weights.Layer.LINEAR16:
        min_val = layer.min_val
        max_val = layer.max_val
        uint16_data = np.frombuffer(data, dtype=np.uint16)
        scale = (max_val - min_val) / 65535.0
        arr = min_val + uint16_data.astype(np.float32) * scale
    else:
        raise ValueError(f'Unknown encoding {encoding}')
    arr = arr.reshape(dims)
    return arr

with open('leela-network.pb', 'rb') as f:
    net = net_pb2.Net()
    net.ParseFromString(f.read())

weights = net.weights
# store in dict
params = {}

# helper to add
def add_param(name, arr):
    params[name] = torch.from_numpy(arr).float()

# input conv
if weights.HasField('input'):
    conv = weights.input
    for field in conv.DESCRIPTOR.fields:
        if conv.HasField(field.name):
            arr = decode_layer(getattr(conv, field.name))
            if arr is not None:
                add_param(f'input.{field.name}', arr)
                print(f'input.{field.name} shape', arr.shape)
# residual blocks
for i, res in enumerate(weights.residual):
    for field in res.DESCRIPTOR.fields:
        if res.HasField(field.name):
            sub = getattr(res, field.name)
            if field.name in ['conv1', 'conv2', 'se', 'se_bias']:
                for sfield in sub.DESCRIPTOR.fields:
                    if sub.HasField(sfield.name):
                        arr = decode_layer(getattr(sub, sfield.name))
                        if arr is not None:
                            add_param(f'residual.{i}.{field.name}.{sfield.name}', arr)
                            print(f'residual.{i}.{field.name}.{sfield.name} shape', arr.shape)
            else:
                arr = decode_layer(sub)
                if arr is not None:
                    add_param(f'residual.{i}.{field.name}', arr)
                    print(f'residual.{i}.{field.name} shape', arr.shape)
# policy head
for field_name in ['policy', 'policy1']:
    if weights.HasField(field_name):
        conv = getattr(weights, field_name)
        for subfield in conv.DESCRIPTOR.fields:
            if conv.HasField(subfield.name):
                arr = decode_layer(getattr(conv, subfield.name))
                if arr is not None:
                    add_param(f'{field_name}.{subfield.name}', arr)
                    print(f'{field_name}.{subfield.name} shape', arr.shape)
# ip fields
for field in weights.DESCRIPTOR.fields:
    if field.name.startswith('ip'):
        if weights.HasField(field.name):
            arr = decode_layer(getattr(weights, field.name))
            if arr is not None:
                add_param(field.name, arr)
                print(f'{field.name} shape', arr.shape)
# value head
if weights.HasField('value'):
    conv = weights.value
    for subfield in conv.DESCRIPTOR.fields:
        if conv.HasField(subfield.name):
            arr = decode_layer(getattr(conv, subfield.name))
            if arr is not None:
                add_param(f'value.{subfield.name}', arr)
                print(f'value.{subfield.name} shape', arr.shape)
print('Total parameters:', len(params))
# save as torch state_dict
torch.save(params, '/app/leela-network-pytorch.pth')
EOF
